import{_ as o,E as t,c as a,J as r,a2 as n,o as s}from"./chunks/framework.VipzY1JJ.js";const _=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"portals/index.md","filePath":"portals/index.md"}'),i={name:"portals/index.md"},l=n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The ambition of Arcsecond is to offer professional-quality software for astronomers and observatories to manage data, execute night operations and perform the best astronomical observations possible. It is built on top of years of experience of professional software development following a 10-years period of astronomical research, and especially 4 years spent in Chile, working for the European Southern Observatory (<a href="https://eso.org" target="_blank" rel="noreferrer">ESO</a>) at the <a href="https://www.arcsecond.io/observingsites/2ac73126-e183-4e56-b04a-03e4f20dced4" target="_blank" rel="noreferrer">La Silla Observatory</a>.</p><p>Arcsecond was initiated to bring to the web a well-known macOS app, called iObserve. It is now expanding to offer powerful portals to small and medium-size observatories. Moreover, Arcsecond is being transformed to work not only in the cloud, but also in self-hosted environments.</p><p>As of today (April 2023), Arcsecond is only available in the cloud, but you can register for the beta in <a href="https://www.arcsecond.io/self-hosting" target="_blank" rel="noreferrer">https://www.arcsecond.io/self-hosting</a> (expected around end 2023).</p><h1 id="oma" tabindex="-1">OMA <a class="header-anchor" href="#oma" aria-label="Permalink to &quot;OMA&quot;">​</a></h1><p>OMA stands for &quot;<a href="https://oma.astrofisicamas.cl" target="_blank" rel="noreferrer">Observatorio Mancomunado de Astrofísica</a>&quot;. It is a consortium of Chilean Universities, coordinated by the Millennium Institute of Astrophysics (MAS) that operates a telescope located in <a href="https://www.arcsecond.io/observingsites/1003d9eb-5f4b-4b16-81f4-1529e52e0959" target="_blank" rel="noreferrer">El Sauce Observatory</a>, in the Atacama desert.</p><p>OMA is the first Observatory Portal of Arcsecond, and is used throughout this documentation to illustrate it with images taken in real conditions.</p>',7);function c(d,p,f,h,m,u){const e=t("ThemedImage");return s(),a("div",null,[l,r(e,{prefix:"introduction-oma-public-welcome",alt:"OMA Public Homepage"})])}const w=o(i,[["render",c]]);export{_ as __pageData,w as default};
